export function mountTaskWizard(container, options = {}) {
  let _state = 'Info';
  let _cleanup = null;
  let _surfaceEl = null;

  const _panel = document.createElement('div');
  _panel.className = 'spec-flow spec-flow--TaskWizard';

  function _render(state, data) {
    if (_cleanup) { _cleanup(); _cleanup = null; }
    const _el = document.createElement('div');
    _el.className = 'spec-flow-state spec-flow-state--' + state;
    switch (state) {
      case 'Info':
        if (typeof mountWizardStep1 === 'function') _cleanup = mountWizardStep1(_el, { dispatch, data });
        break;
      case 'Options':
        if (typeof mountWizardStep2 === 'function') _cleanup = mountWizardStep2(_el, { dispatch, data });
        break;
      case 'Review':
        if (typeof mountWizardStep3 === 'function') _cleanup = mountWizardStep3(_el, { dispatch, data });
        break;
      case 'Done':
        if (typeof mountWizardStep3 === 'function') _cleanup = mountWizardStep3(_el, { dispatch, data });
        break;
    }
    if (_surfaceEl) {
      _panel.replaceChild(_el, _surfaceEl);
    } else {
      _panel.appendChild(_el);
    }
    _surfaceEl = _el;
  }

  function _go(newState, data, skipHistory) {
    _state = newState;
    _render(newState, data);
    if (!skipHistory && options.history !== false) {
      history.pushState({ flowState: newState }, '', '#' + newState);
    }
  }

  function dispatch(event, arg) {
    switch (_state) {
      case 'Info': {
        if (event === 'next') {
          if (!(title != "")) return;
          _go('Options', null);
        }
        break;
      }
      case 'Options': {
        if (event === 'back') {
          _go('Info', null);
        }
        else if (event === 'next') {
          _go('Review', null);
        }
        break;
      }
      case 'Review': {
        if (event === 'back') {
          _go('Options', null);
        }
        else if (event === 'submit') {
          if (!(confirmed)) return;
          _go('Done', null);
        }
        break;
      }
      case 'Done': {
        if (event === 'restart') {
          _go('Info', null);
        }
        break;
      }
    }
  }

  const _onPopState = (e) => {
    const s = (e.state && e.state.flowState) || 'Info';
    _state = s;
    _render(s, null);
  };

  if (options.history !== false) {
    window.addEventListener('popstate', _onPopState);
    history.replaceState({ flowState: 'Info' }, '', '#Info');
  }

  container.appendChild(_panel);
  _render('Info', null);

  return () => {
    if (options.history !== false) window.removeEventListener('popstate', _onPopState);
    if (_cleanup) _cleanup();
    _panel.remove();
  };
}


export function createTasksAPI(params = {}) {
  return createSource({
    endpoint: 'http://localhost:4000/api/tasks',
    method: 'GET',
    cacheTtl: 60000,
    retryAttempts: 3,
    retryStrategy: 'exponential',
    ...params,
  });
}

